head.script:
// LoginDTO loginDTO = LoginUtil.getLoginDTO(request);



// 화면
scwin.onpageload = function () {
    scwin.userHomeClsCd = $c.data.getMemInfo("userHomeClsCd"); // 사용자소속구분코드
    scwin.sysAdminYn = $c.data.getMemInfo("sysAdminYn") + "";
    scwin.strFromDate = $c.date.getServerDateTime("yyyyMM") + "01";
    scwin.strLastDate = $c.date.getLastDateOfMonth(scwin.strFromDate);
    scwin.strToDate = scwin.strFromDate.substring(0, 6) + scwin.strLastDate;

    scwin.pos_ctrt = 0;
    scwin.g_sUserId = $c.data.getMemInfo("userId");
    scwin.g_sUserNm = $c.data.getMemInfo("userNm");
    scwin.g_sAcctDeptCd = $c.data.getMemInfo("acctDeptCd");
    scwin.g_sAcctDeptNm = $c.data.getMemInfo("acctDeptNm");
    scwin.g_sEmpNo = $c.data.getMemInfo("epId");
    scwin.currentDate = $c.date.getServerDateTime("yyyyMMdd");

    scwin.manager = "";
    scwin.managerYn = ""; //관리자 여부

	const codeOptions = [
        { grpCd: "ZZ021", compID: "lc_apprvStsCd", opt: { "range": "2,1" } } // 상태
    ]
    $c.data.setCommonCode(codeOptions)
};

//----------------------------------------------------------
// 화면로딩시 UDC 호출
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function () {
    scwin.f_ContentsDisable();
    $c.gus.cfDisableBtn([btn_Create, btn_Copy, btn_Update, btn_Cancel, btn_Save, btn_Delete, btn_Aprv]);

    // f_createHeader();
    ed_ctrtStDt.setValue(scwin.strFromDate);
    ed_ctrtEndDt.setValue(scwin.strToDate);
	/*
    const codeOptions = [
        { grpCd: "ZZ021", compID: "lc_apprvStsCd", opt: { "range": "2,1" } } // 상태
    ]
    $c.data.setCommonCode(codeOptions) */
    // TEST DATA
    // ds_retrieveCtrtClnt.set("ctrtClntNo", 316381)
    //ed_ctrtStDt.setValue("20260101");
};


//-------------------------------------------------------------------------
// 공통코드가 셋팅이 되고 scwin.ondataload 이벤트가 호출
//-------------------------------------------------------------------------
scwin.ondataload = function () {
    lc_apprvStsCd.addItem("99", "회수")
};



// 귀속부서 공통팝업 
scwin.openAcctDeptPopup = function (udcObj, codeInput, nameInput, codeVal, nameVal) {

    var pWhere = ed_ctrtStDt.getValue().substring(0, 4) + ",,,,,,,,," + "000";

    udcObj.cfCommonPopUp(
        function(ret){
            scwin.commonAcctDeptCallback(codeInput, nameInput, ret);
        },
        codeVal,
        nameVal,
        "T",
        null, null, null, null,
        pWhere,
        "450",
        "500",
        null, null, null,
        "F",
        null,
        null
    );
};

// 귀속부서 공통 콜백
scwin.commonAcctDeptCallback = function(codeInput, nameInput, ret){

    if (!ret || ret[0] == "N/A") {
        return;
    }

    codeInput.setValue(ret[0]);
    nameInput.setValue(ret[1]);
};

// 클릭
scwin.udc_acctDeptCd_onclickEvent = function () {
    scwin.openAcctDeptPopup(
        udc_acctDeptCd,
        ed_acctDeptCd,
        ed_acctDeptNm,
        ed_acctDeptCd.getValue(),
        ed_acctDeptNm.getValue()
    );
};

// blur
scwin.udc_acctDeptCd_onblurCodeEvent = function () {
    scwin.openAcctDeptPopup(
        udc_acctDeptCd,
        ed_acctDeptCd,
        ed_acctDeptNm,
        ed_acctDeptCd.getValue(),
        ""
    );
};

// name 변경
scwin.udc_acctDeptCd_onviewchangeNameEvent = function () {
    scwin.openAcctDeptPopup(
        udc_acctDeptCd,
        ed_acctDeptCd,
        ed_acctDeptNm,
        "",
        ed_acctDeptNm.getValue()
    );
};

// 클릭
scwin.udc_acctDeptCd2_onclickEvent = function () {
    scwin.openAcctDeptPopup(
        udc_acctDeptCd2,
        ed_acctDeptCd2,
        ed_acctDeptNm2,
        ed_acctDeptCd2.getValue(),
        ed_acctDeptNm2.getValue()
